CONOUT_CHAR_1:
        PUSH BC                          ; $04FD  C5
CONOUT_CHAR_2:
        PUSH DE                          ; $04FE  D5
CONOUT_CHAR_3:
        PUSH HL                          ; $04FF  E5
CONOUT_CHAR_4:
        LD E,A                           ; $0500  5F
CONOUT_CHAR_5:
        LD C,$02                         ; $0501  0E 02
CONOUT_CHAR_6:
        CALL BDOS_VEC                    ; $0503  CD 05 00
CONOUT_CHAR_7:
        POP HL                           ; $0506  E1
CONOUT_CHAR_8:
        POP DE                           ; $0507  D1
CONOUT_CHAR_9:
        POP BC                           ; $0508  C1
CONOUT_CHAR_10:
        POP AF                           ; $0509  F1
CONOUT_CHAR_11:
        RET                              ; $050A  C9
CONOUT_CHAR_12:
        DEFB    $B7                                              ; $050B
CONOUT_CHAR_13:
        DEFB    $00,$00                                          ; $050C
CONOUT_CHAR_14:
        DEFB    $00                                              ; $050E
CONOUT_CHAR_15:
        DEFB    $00,$00                                          ; $050F
CONOUT_CHAR_16:
        DEFB    $01                                              ; $0511
CONOUT_CHAR_17:
        DEFB    $00                                              ; $0512
CONOUT_CHAR_18:
        DEFB    $00                                              ; $0513
CONOUT_CHAR_19:
        DEFB    $00                                              ; $0514
CONOUT_CHAR_20:
        DEFB    $00                                              ; $0515
CONOUT_CHAR_21:
        DEFB    $00                                              ; $0516
CONOUT_CHAR_22:
        DEFB    $00                                              ; $0517
CONOUT_CHAR_23:
        DEFB    $00                                              ; $0518
CONOUT_CHAR_24:
        DEFS    41, $00    ; $0519  fill
CONOUT_CHAR_25:
        DEFB    $00,$0E,$0D,$0C,$0B,$0A,$09                      ; $0542
