CONOUT_CHAR_26:
        DEFW    TPA_START                ; $0552
        DEFB    $02,$03,$04,$05,$06,$07,$08,$09,$0A,$0B,$0C      ; $0554
CONOUT_CHAR_27:
        DEFB    $00,$0F,$07,$03                                  ; $055F
        DEFW    CONSOLE_STATUS_8         ; $0563
        DEFB    $06,$0D                                          ; $0565
        DEFW    TPA_START_3              ; $0567
        DEFB    $08,$0C,$04                                      ; $0569
CONOUT_CHAR_28:
        DEFS    30, $00    ; $056C  fill
CONOUT_CHAR_29:
        DEFB    $49,$41,$42,$54                                  ; $058A
CONOUT_CHAR_30:
        DEFB    $09,"   APPLE ][ CP/M",$0D,$0A      ; $058E
